/* ============================================================
   MATH: ports of sklearn's exact transform steps
   ============================================================ */

// Acklam's rational approximation of the inverse normal CDF
function normPpf(p) {
  if (p <= 0) return -Infinity;
  if (p >= 1) return Infinity;
  const a = [-3.969683028665376e+01, 2.209460984245205e+02, -2.759285104469687e+02,
             1.383577518672690e+02, -3.066479806614716e+01, 2.506628277459239e+00];
  const b = [-5.447609879822406e+01, 1.615858368580409e+02, -1.556989798598866e+02,
             6.680131188771972e+01, -1.328068155288572e+01];
  const c = [-7.784894002430293e-03, -3.223964580411365e-01, -2.400758277161838e+00,
             -2.549732539343734e+00, 4.374664141464968e+00, 2.938163982698783e+00];
  const d = [7.784695709041462e-03, 3.224671290700398e-01, 2.445134137142996e+00,
             3.754408661907416e+00];
  const p_low = 0.02425, p_high = 1 - p_low;
  let q, r;
  if (p < p_low) {
    q = Math.sqrt(-2 * Math.log(p));
    return (((((c[0]*q+c[1])*q+c[2])*q+c[3])*q+c[4])*q+c[5]) /
           ((((d[0]*q+d[1])*q+d[2])*q+d[3])*q+1);
  } else if (p <= p_high) {
    q = p - 0.5; r = q*q;
    return (((((a[0]*r+a[1])*r+a[2])*r+a[3])*r+a[4])*r+a[5])*q /
           (((((b[0]*r+b[1])*r+b[2])*r+b[3])*r+b[4])*r+1);
  } else {
    q = Math.sqrt(-2 * Math.log(1-p));
    return -(((((c[0]*q+c[1])*q+c[2])*q+c[3])*q+c[4])*q+c[5]) /
             ((((d[0]*q+d[1])*q+d[2])*q+d[3])*q+1);
  }
}

function linInterp(x, xp, fp) {
  const n = xp.length;
  if (x <= xp[0]) return fp[0];
  if (x >= xp[n - 1]) return fp[n - 1];
  let lo = 0, hi = n - 1;
  while (hi - lo > 1) {
    const mid = (lo + hi) >> 1;
    if (xp[mid] <= x) lo = mid; else hi = mid;
  }
  const t = (x - xp[lo]) / (xp[hi] - xp[lo]);
  return fp[lo] + t * (fp[hi] - fp[lo]);
}

const BOUNDS_THRESHOLD = 1e-7;
const CLIP_BOUND = 5.19933758270342;

function quantileTransformCol(x, quantiles, references) {
  const n = quantiles.length;
  const qRev = new Array(n), rRev = new Array(n);
  for (let i = 0; i < n; i++) {
    qRev[i] = -quantiles[n - 1 - i];
    rRev[i] = -references[n - 1 - i];
  }
  const u1 = linInterp(x, quantiles, references);
  const u2 = -linInterp(-x, qRev, rRev);
  let u = 0.5 * (u1 + u2);
  if (x - BOUNDS_THRESHOLD < quantiles[0]) u = 0;
  if (x + BOUNDS_THRESHOLD > quantiles[n - 1]) u = 1;
  let z = normPpf(u);
  z = Math.min(Math.max(z, -CLIP_BOUND), CLIP_BOUND);
  return z;
}

export function runModel(rawInput) {
  const p = MODEL_PARAMS;
  const feats = p.feature_names;

  let x = feats.map((f, i) => {
    const v = rawInput[f];
    return (v === null || v === undefined || Number.isNaN(v)) ? p.imputer_medians[i] : v;
  });

  x = x.map((v, i) => {
    const col = p.qt_quantiles.map((row) => row[i]);
    return quantileTransformCol(v, col, p.qt_references);
  });

  x = x.map((v, i) => (v - p.scaler_mean[i]) / p.scaler_scale[i]);

  let decision = p.intercept;
  const gamma = p.gamma;
  for (let s = 0; s < p.support_vectors.length; s++) {
    const sv = p.support_vectors[s];
    let sq = 0;
    for (let j = 0; j < sv.length; j++) {
      const d = x[j] - sv[j];
      sq += d * d;
    }
    decision += p.dual_coef[s] * Math.exp(-gamma * sq);
  }

  const lut = p.percentile_lookup;
  let pct;
  if (decision <= lut[0]) pct = 0;
  else if (decision >= lut[lut.length - 1]) pct = 100;
  else {
    pct = 100;
    for (let i = 0; i < lut.length - 1; i++) {
      if (decision >= lut[i] && decision <= lut[i + 1]) {
        const t = (decision - lut[i]) / (lut[i + 1] - lut[i]);
        pct = i + t;
        break;
      }
    }
  }
  return { decision, percentile: pct };
}

function bandFor(pct) {
  if (pct < 33) return { label: "Lower relative position", key: "low" };
  if (pct < 66) return { label: "Middle relative position", key: "mid" };
  return { label: "Higher relative position", key: "high" };
}

